<script setup lang="ts">
import{onMounted,ref}from'vue';import{useRouter}from'vue-router';import{UploadCloud,FileCheck2,CheckCircle2,AlertCircle}from'lucide-vue-next';import LoadingSpinner from '@/components/ui/LoadingSpinner.vue';import{catalogService}from '@/services/catalogService';import{importService}from '@/services/importService';import{apiErrorMessage}from '@/composables/useApiError';import type{Categoria,ImportacaoArquivo}from '@/types/api';
const router=useRouter(),file=ref<File|null>(null),categories=ref<Categoria[]>([]),categoryId=ref(''),origin=ref(''),path=ref(''),dragging=ref(false),sending=ref(false),progress=ref(0),success=ref<ImportacaoArquivo|null>(null),error=ref('');
onMounted(async()=>{try{categories.value=await catalogService.categories()}catch{/* campo fica vazio */}});function select(files:FileList|null){error.value='';const picked=files?.[0];if(!picked)return;if(!picked.name.toLowerCase().endsWith('.pes')){error.value='Selecione um arquivo no formato .PES.';return}file.value=picked;success.value=null}function drop(e:DragEvent){dragging.value=false;select(e.dataTransfer?.files??null)}function size(n:number){return n<1048576?`${(n/1024).toFixed(1)} KB`:`${(n/1048576).toFixed(1)} MB`}async function submit(){if(!file.value)return;sending.value=true;error.value='';progress.value=0;try{const result=await importService.single(file.value,{caminho_relativo:path.value.trim()||undefined,identificacao_origem:origin.value.trim()||undefined},n=>progress.value=n);if(categoryId.value)await catalogService.categorize(result.desenho_id,Number(categoryId.value));success.value=result}catch(e){error.value=apiErrorMessage(e,'Não foi possível importar esta matriz.')}finally{sending.value=false}}function reset(){file.value=null;success.value=null;error.value='';progress.value=0}
</script>
<template><section class="mx-auto max-w-4xl"><h1 class="font-serif text-4xl text-purple md:text-5xl">Importar matriz</h1><p class="mt-2 text-muted">Selecione um arquivo .PES para adicionar ao seu catálogo.</p><div v-if="success" class="mt-9 rounded-3xl border border-line bg-white p-10 text-center shadow-soft"><CheckCircle2 class="mx-auto text-sage" :size="54"/><h2 class="mt-4 font-serif text-3xl text-purple">Matriz importada com sucesso!</h2><p class="mt-2 text-muted">{{success.nome}} já está disponível no seu acervo.</p><div class="mt-6 flex flex-wrap justify-center gap-3"><button class="primary-button" @click="router.push('/')">Ver no catálogo</button><button class="rounded-xl border border-line px-5 py-3 font-semibold text-purple" @click="reset">Importar outra</button></div></div><form v-else class="mt-9 rounded-3xl border border-line bg-white p-5 shadow-sm md:p-8" @submit.prevent="submit"><label :class="['flex min-h-64 cursor-pointer flex-col items-center justify-center rounded-2xl border-2 border-dashed p-6 text-center transition',dragging?'border-terracotta bg-[#FFF7F3]':'border-line bg-cream']" @dragover.prevent="dragging=true" @dragleave.prevent="dragging=false" @drop.prevent="drop"><input class="sr-only" type="file" accept=".pes,.PES" :disabled="sending" @change="select(($event.target as HTMLInputElement).files)"/><FileCheck2 v-if="file" :size="45" class="text-sage"/><UploadCloud v-else :size="45" class="text-terracotta"/><strong class="mt-4 text-purple">{{file?file.name:'Arraste seu arquivo .PES aqui'}}</strong><span class="mt-1 text-sm text-muted">{{file?size(file.size):'ou clique para selecionar o arquivo'}}</span><span v-if="!file" class="mt-5 rounded-xl bg-white px-4 py-2 text-sm font-semibold text-terracotta shadow-sm">Selecionar arquivo</span></label><div class="mt-7 grid gap-5 md:grid-cols-2"><label class="text-sm font-medium text-purple">Categoria <span class="font-normal text-muted">(opcional)</span><select v-model="categoryId" class="field mt-2" :disabled="sending"><option value="">Sem categoria</option><option v-for="c in categories" :key="c.id" :value="String(c.id)">{{c.nome}}</option></select></label><label class="text-sm font-medium text-purple">Identificação da origem <span class="font-normal text-muted">(opcional)</span><input v-model="origin" class="field mt-2" maxlength="255" placeholder="Ex.: Pendrive Azul ou Acervo antigo" :disabled="sending"/></label><label class="text-sm font-medium text-purple md:col-span-2">Caminho relativo de origem <span class="font-normal text-muted">(opcional)</span><input v-model="path" class="field mt-2" maxlength="1024" placeholder="Ex.: flores/rosas/matriz.pes" :disabled="sending"/></label></div><div v-if="error" class="mt-5 flex items-start gap-2 rounded-xl bg-red-50 p-4 text-sm text-red-700"><AlertCircle :size="19" class="shrink-0"/>{{error}}</div><div v-if="sending" class="mt-6"><div class="mb-2 flex justify-between text-sm text-muted"><span>Processando matriz e gerando preview…</span><span>{{progress}}%</span></div><div class="h-2 overflow-hidden rounded-full bg-line"><div class="h-full bg-terracotta transition-all" :style="{width:`${Math.max(progress,8)}%`}"></div></div></div><div class="mt-7 flex flex-wrap items-center gap-3"><button class="primary-button" :disabled="!file||sending"><LoadingSpinner v-if="sending"/><UploadCloud v-else :size="19"/>{{sending?'Processando…':'Importar matriz'}}</button><button v-if="file&&!sending" type="button" class="rounded-xl px-4 py-3 text-sm font-medium text-muted" @click="reset">Selecionar outro arquivo</button></div></form></section></template>
